def matrix_power_period(T,m,maxN=_sage_const_6000 ):
    R=Integers(m); Tm=T.change_ring(R)
    seen={}; P=Tm; N=_sage_const_1 
    while N<=maxN:
        key=tuple(P.list())
        if key in seen: return seen[key], N-seen[key]
        seen[key]=N; P=P*Tm; N+=_sage_const_1 
    return None,None

